bool isMatch(char* s, char* p) {
    int m = (int)strlen(s), n = (int)strlen(p);
    bool* dp = (bool*)calloc((m+1)*(n+1), sizeof(bool));
    #define D(i,j) dp[(i)*(n+1)+(j)]
    D(0,0) = true;
    for (int j = 1; j <= n; j++)
        if (p[j-1] == '*') D(0,j) = D(0,j-1);
    for (int i = 1; i <= m; i++)
        for (int j = 1; j <= n; j++) {
            if (p[j-1] == '*') D(i,j) = D(i,j-1) || D(i-1,j);
            else if (p[j-1] == '?' || s[i-1] == p[j-1]) D(i,j) = D(i-1,j-1);
        }
    bool ans = D(m,n);
    free(dp);
    return ans;
}
